/* ===== lib/logger.js ===== */
/**
 * Shared logger for content scripts. Prefixes all messages for easy filtering.
 */
if (!globalThis.VietnamVisaLog) {
  globalThis.VietnamVisaLog = {
    prefix: '[Vietnam e-Visa]',

    debug(...args) {
      console.debug(this.prefix, ...args);
    },

    info(...args) {
      console.info(this.prefix, ...args);
    },

    warn(...args) {
      console.warn(this.prefix, ...args);
    },

    error(...args) {
      console.error(this.prefix, ...args);
    },

    step(name, detail) {
      this.debug(`step: ${name}`, detail ?? '');
    },

    stepError(name, err) {
      this.error(`step failed: ${name}`, err?.message ?? err, err?.stack ?? '');
    },
  };
}


/* ===== lib/yaml.js ===== */
/**
 * Minimal YAML parser for profile.yaml (subset: maps, lists, strings, bools, numbers).
 */
(() => {
  if (globalThis.YamlParser) return;

  globalThis.YamlParser = (() => {
  function parse(text) {
    const lines = text.replace(/\r\n/g, '\n').split('\n');
    const root = {};
    const stack = [{ indent: -1, value: root, type: 'map' }];
    let i = 0;

    while (i < lines.length) {
      const raw = lines[i];
      i += 1;
      if (!raw.trim() || raw.trim().startsWith('#')) continue;

      const indent = raw.match(/^ */)[0].length;
      const trimmed = raw.trim();

      while (stack.length > 1 && indent <= stack[stack.length - 1].indent) {
        stack.pop();
      }

      const ctx = stack[stack.length - 1];

      if (trimmed.startsWith('- ')) {
        const itemText = stripInlineComment(trimmed.slice(2).trim());
        if (ctx.type !== 'list') {
          throw new Error(`Unexpected list item at line: ${raw}`);
        }
        if (itemText === '') {
          const obj = {};
          ctx.value.push(obj);
          stack.push({ indent, value: obj, type: 'map' });
        } else if (itemText.includes(':')) {
          const obj = parseKeyValue(itemText);
          ctx.value.push(obj);
          if (typeof obj === 'object' && obj !== null && !Array.isArray(obj)) {
            stack.push({ indent, value: obj, type: 'map' });
          }
        } else {
          ctx.value.push(parseScalar(itemText));
        }
        continue;
      }

      const colonIdx = trimmed.indexOf(':');
      if (colonIdx === -1) continue;

      const key = trimmed.slice(0, colonIdx).trim();
      const rest = stripInlineComment(trimmed.slice(colonIdx + 1).trim());

      if (rest === '') {
        const peek = lines[i];
        const nextIsList = peek && /^\s*-\s/.test(peek);
        const child = nextIsList ? [] : {};
        ctx.value[key] = child;
        stack.push({ indent, value: child, type: nextIsList ? 'list' : 'map' });
      } else if (rest === '[]') {
        ctx.value[key] = [];
        stack.push({ indent, value: ctx.value[key], type: 'list' });
      } else {
        ctx.value[key] = parseScalar(rest);
      }
    }

    return root;
  }

  function parseKeyValue(text) {
    const colonIdx = text.indexOf(':');
    const key = text.slice(0, colonIdx).trim();
    const rest = text.slice(colonIdx + 1).trim();
    const obj = {};
    obj[key] = rest === '' ? {} : parseScalar(rest);
    return obj;
  }

  function stripInlineComment(raw) {
    let inSingle = false;
    let inDouble = false;
    for (let i = 0; i < raw.length; i += 1) {
      const ch = raw[i];
      if (ch === '"' && !inSingle) inDouble = !inDouble;
      if (ch === "'" && !inDouble) inSingle = !inSingle;
      if (ch === '#' && !inSingle && !inDouble) {
        const prev = raw[i - 1];
        if (i === 0 || /\s/.test(prev)) {
          return raw.slice(0, i).trimEnd();
        }
      }
    }
    return raw;
  }

  function parseScalar(raw) {
    raw = stripInlineComment(raw.trim());
    if ((raw.startsWith('"') && raw.endsWith('"')) || (raw.startsWith("'") && raw.endsWith("'"))) {
      return raw.slice(1, -1);
    }
    if (raw === 'true') return true;
    if (raw === 'false') return false;
    if (raw === 'null' || raw === '~') return null;
    if (/^-?\d+$/.test(raw)) return Number(raw);
    if (/^-?\d+\.\d+$/.test(raw)) return Number(raw);
    return raw;
  }

  return { parse };
  })();
})();


/* ===== lib/field-helpers.js ===== */
/**
 * DOM helpers for Ant Design Vue form fields on evisa.gov.vn
 */
(() => {
  if (globalThis.FieldHelpers) return;

  globalThis.FieldHelpers = (() => {
  const nativeInputValueSetter = Object.getOwnPropertyDescriptor(
    window.HTMLInputElement.prototype,
    'value'
  ).set;

  function sleep(ms) {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }

  async function waitFor(fn, timeout = 3000, interval = 100) {
    const start = Date.now();
    while (Date.now() - start < timeout) {
      const result = fn();
      if (result) return result;
      await sleep(interval);
    }
    return null;
  }

  function dispatchInputEvents(el) {
    el.dispatchEvent(new Event('input', { bubbles: true }));
    el.dispatchEvent(new Event('change', { bubbles: true }));
    el.dispatchEvent(new Event('blur', { bubbles: true }));
  }

  function setInputValue(el, value) {
    nativeInputValueSetter.call(el, value);
    dispatchInputEvents(el);
  }

  async function fillInput(id, value) {
    if (value === undefined || value === null || value === '') return;
    const el = document.getElementById(id);
    if (!el) throw new Error(`Input not found: #${id}`);
    el.focus();
    setInputValue(el, String(value));
    await sleep(50);
  }

  async function fillAntDate(id, value) {
    if (!value) return;
    const el = document.getElementById(id);
    if (!el) throw new Error(`Date input not found: #${id}`);

    el.click();
    await sleep(100);
    el.removeAttribute('readonly');
    setInputValue(el, String(value));
    await sleep(50);

    document.body.click();
    await sleep(50);
  }

  function getVisibleDropdowns() {
    return [...document.querySelectorAll('.ant-select-dropdown')].filter((dd) => {
      if (dd.classList.contains('ant-select-dropdown-hidden')) return false;
      const style = window.getComputedStyle(dd);
      return style.display !== 'none' && style.visibility !== 'hidden';
    });
  }

  function findDropdownForSelect(inputId) {
    const listId = `${inputId}_list`;
    const listbox = document.getElementById(listId);
    if (listbox) {
      const dropdown = listbox.closest('.ant-select-dropdown');
      if (dropdown) return dropdown;
    }
    const visible = getVisibleDropdowns();
    return visible.length === 1 ? visible[0] : visible[visible.length - 1] || null;
  }

  function normalizeLabel(value) {
    return String(value)
      .trim()
      .replace(/\s+/g, ' ')
      .replace(/\.$/, '')
      .toLowerCase();
  }

  function getOptionLabel(option) {
    return (
      option.getAttribute('title') ||
      option.querySelector('.ant-select-item-option-content')?.textContent ||
      option.textContent ||
      ''
    ).trim();
  }

  function findBestOption(options, label) {
    const target = normalizeLabel(label);
    if (!target) return null;

    const scored = options
      .map((opt) => {
        const text = getOptionLabel(opt);
        const norm = normalizeLabel(text);
        let score = 0;

        if (norm === target) score = 100;
        else if (text === label.trim()) score = 95;
        else if (norm.includes(target)) score = 80;
        else if (target.includes(norm) && norm.length > 3) score = 70;
        else {
          const targetWords = target.split(/[\s,()]+/).filter(Boolean);
          const optionWords = norm.split(/[\s,()]+/).filter(Boolean);
          const overlap = targetWords.filter((word) =>
            optionWords.some((ow) => ow === word || ow.includes(word) || word.includes(ow))
          ).length;
          score = overlap * 5;
        }

        return { opt, text, score };
      })
      .filter((item) => item.score > 0)
      .sort((a, b) => b.score - a.score);

    return scored[0] || null;
  }

  async function collectSelectOptions(dropdown) {
    const seen = new Map();
    const holder = dropdown.querySelector('.rc-virtual-list-holder');

    async function snapshot() {
      for (const opt of dropdown.querySelectorAll('.ant-select-item-option')) {
        const text = getOptionLabel(opt);
        if (text) seen.set(text, opt);
      }
    }

    await snapshot();

    if (holder && holder.scrollHeight > holder.clientHeight) {
      const step = Math.max(80, Math.floor(holder.clientHeight * 0.8));
      for (let scrollTop = 0; scrollTop <= holder.scrollHeight; scrollTop += step) {
        holder.scrollTop = scrollTop;
        await sleep(80);
        await snapshot();
      }
      holder.scrollTop = 0;
      await sleep(50);
    }

    return [...seen.entries()].map(([text, opt]) => ({ text, opt }));
  }

  async function typeSelectSearch(input, text) {
    input.focus();
    input.click();
    await sleep(50);

    nativeInputValueSetter.call(input, '');
    input.dispatchEvent(new Event('input', { bubbles: true }));
    await sleep(50);

    const value = String(text);
    for (let i = 0; i < value.length; i += 1) {
      const next = value.slice(0, i + 1);
      nativeInputValueSetter.call(input, next);
      input.dispatchEvent(
        new InputEvent('input', {
          bubbles: true,
          data: value[i],
          inputType: 'insertText',
        })
      );
      await sleep(15);
    }

    await sleep(400);
  }

  function clickOption(option) {
    option.dispatchEvent(new MouseEvent('mousedown', { bubbles: true, cancelable: true }));
    option.click();
  }

  async function closeDropdowns() {
    document.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape', bubbles: true }));
    await sleep(100);
    document.body.click();
    await sleep(100);
  }

  async function fillAntSelect(inputId, label, { searchable = true } = {}) {
    if (!label) return;

    globalThis.VietnamVisaLog?.debug(`select: opening #${inputId} for "${label}"`);
    await closeDropdowns();

    const input = document.getElementById(inputId);
    if (!input) throw new Error(`Select input not found: #${inputId}`);

    const select = input.closest('.ant-select');
    if (!select) throw new Error(`Select wrapper not found for #${inputId}`);

    if (select.classList.contains('ant-select-disabled')) {
      throw new Error(`Select is disabled: #${inputId}`);
    }

    const selector = select.querySelector('.ant-select-selector');
    selector.dispatchEvent(new MouseEvent('mousedown', { bubbles: true }));
    selector.click();
    await sleep(250);

    const searchTerms = searchable
      ? [String(label), String(label).split(/[,(]/)[0].trim()].filter(
          (term, index, arr) => term && arr.indexOf(term) === index
        )
      : [String(label)];

    let chosen = null;
    let lastOptions = [];

    for (const term of searchTerms) {
      if (searchable) {
        await typeSelectSearch(input, term);
      }

      const dropdown = await waitFor(() => findDropdownForSelect(inputId), 3000);
      if (!dropdown) {
        globalThis.VietnamVisaLog?.warn(`select: dropdown not open for #${inputId}, term="${term}"`);
        continue;
      }

      lastOptions = await collectSelectOptions(dropdown);
      const match = findBestOption(
        lastOptions.map((item) => item.opt),
        label
      );

      if (match) {
        chosen = match;
        globalThis.VietnamVisaLog?.debug(`select: matched #${inputId}`, match.text, `(search: "${term}")`);
        clickOption(match.opt);
        break;
      }

      globalThis.VietnamVisaLog?.debug(
        `select: no match for #${inputId} with term "${term}", options:`,
        lastOptions.slice(0, 8).map((item) => item.text)
      );
      await closeDropdowns();
      selector.click();
      await sleep(200);
    }

    if (!chosen) {
      const sample = lastOptions.slice(0, 12).map((item) => item.text);
      globalThis.VietnamVisaLog?.error(`select: option not found for #${inputId}`, {
        wanted: label,
        sample,
      });
      throw new Error(
        `Option "${label}" not found for #${inputId}. Sample options: ${sample.join(', ')}`
      );
    }

    await sleep(200);
    await closeDropdowns();

    const selectedItem = select.querySelector('.ant-select-selection-item')?.textContent?.trim();
    const selectedText =
      selectedItem || (normalizeLabel(input.value) === normalizeLabel(label) ? label : '');

    if (!selectedText && !select.classList.contains('ant-select-auto-complete')) {
      throw new Error(`Selection not applied for #${inputId} (wanted "${label}")`);
    }

    globalThis.VietnamVisaLog?.debug(`select: applied #${inputId}`, selectedText || label);
  }

  async function fillAntAutoComplete(inputId, value) {
    if (!value) return;
    const input = document.getElementById(inputId);
    if (!input) throw new Error(`Autocomplete not found: #${inputId}`);

    input.focus();
    setInputValue(input, String(value));
    await sleep(400);

    const dropdown = findDropdownForSelect(inputId);
    if (dropdown) {
      const option = dropdown.querySelector('.ant-select-item-option');
      if (option) {
        option.click();
        await sleep(100);
        return;
      }
    }
  }

  async function fillRadioByContainer(containerSelector, value) {
    const container = document.querySelector(containerSelector);
    if (!container) throw new Error(`Radio container not found: ${containerSelector}`);

    const radioValue = value ? '1' : '0';
    const radio = container.querySelector(`.ant-radio-input[value="${radioValue}"]`);
    if (!radio) throw new Error(`Radio value ${radioValue} not found in ${containerSelector}`);

    radio.closest('label')?.click() || radio.click();
    await sleep(50);
  }

  async function fillRadioByQuestion(questionText, value) {
    const containers = [...document.querySelectorAll('.ant-col.flex.justify-between, .flex.justify-between')];
    const row = containers.find((el) => el.textContent.includes(questionText));
    if (!row) throw new Error(`Radio question not found: ${questionText}`);

    const group = row.querySelector('.ant-radio-group');
    if (!group) throw new Error(`Radio group not found for: ${questionText}`);

    const radioValue = value ? '1' : '0';
    const radio = group.querySelector(`.ant-radio-input[value="${radioValue}"]`);
    if (!radio) throw new Error(`Radio not found for: ${questionText}`);

    radio.closest('label')?.click() || radio.click();
    await sleep(50);
  }

  async function fillRadioByName(nameSelector, value) {
    const map = { single: '0', multiple: '1', full: 'D', year_only: 'Y' };
    const radioValue = map[value] ?? (value ? '1' : '0');
    const container = document.querySelector(nameSelector);
    if (!container) throw new Error(`Radio container not found: ${nameSelector}`);

    const radio = container.querySelector(`.ant-radio-input[value="${radioValue}"]`);
    if (!radio) throw new Error(`Radio value ${radioValue} not found in ${nameSelector}`);

    radio.closest('label')?.click() || radio.click();
    await sleep(50);
  }

  async function fillCheckboxById(id, checked) {
    const el = document.getElementById(id);
    if (!el) throw new Error(`Checkbox not found: #${id}`);
    await fillCheckbox(el, checked);
  }

  async function fillCheckbox(inputEl, checked) {
    const el = typeof inputEl === 'string' ? document.querySelector(inputEl) : inputEl;
    if (!el) throw new Error('Checkbox not found');

    const checkbox = el.classList?.contains('ant-checkbox-input')
      ? el
      : el.querySelector?.('.ant-checkbox-input') || el;

    const isChecked = checkbox.checked;
    if (Boolean(checked) !== isChecked) {
      checkbox.closest('label')?.click() || checkbox.click();
      await sleep(50);
    }
  }

  async function fillCheckboxByText(text, checked) {
    const labels = [...document.querySelectorAll('.ant-checkbox-wrapper')];
    const label = labels.find((l) => l.textContent.includes(text));
    if (!label) throw new Error(`Checkbox not found for text: ${text}`);

    const checkbox = label.querySelector('.ant-checkbox-input');
    await fillCheckbox(checkbox, checked);
  }

  function findTableByColumnHeaders(requiredHeaders) {
    for (const wrapper of document.querySelectorAll('.ant-table-wrapper')) {
      const headers = [...wrapper.querySelectorAll('th')].map((th) => th.textContent.trim());
      if (requiredHeaders.every((text) => headers.some((h) => h.includes(text)))) {
        return wrapper;
      }
    }
    return null;
  }

  function getTableDataRows(tableWrapper) {
    const tbody = tableWrapper?.querySelector('.ant-table-tbody');
    if (!tbody) return [];

    return [...tbody.querySelectorAll('tr')].filter(
      (row) => !row.classList.contains('ant-table-measure-row') && !row.classList.contains('ant-table-placeholder')
    );
  }

  function findVisitHistoryTable() {
    return findTableByColumnHeaders(['From date', 'Purpose of trip']);
  }

  function findChildrenTable() {
    return findTableByColumnHeaders(['Full name']);
  }

  async function clickPlusTableRow(tableWrapper, label) {
    const plus = tableWrapper?.querySelector('.ant-table-summary img[alt="PlusCircle"]');
    if (!plus) throw new Error(`${label} plus button not found`);
    plus.click();
    await sleep(300);
  }

  async function fillPickerInput(input, value) {
    if (!value || !input) return;

    input.click();
    await sleep(100);
    input.removeAttribute('readonly');
    setInputValue(input, String(value));
    await sleep(50);
    document.body.click();
    await sleep(50);
  }

  async function fillVisitHistoryRow(row, visit) {
    const dateInputs = row.querySelectorAll('.ant-picker-input input');
    if (dateInputs.length < 2) throw new Error('Visit row date inputs not found');

    await fillPickerInput(dateInputs[0], visit.from_date);
    await fillPickerInput(dateInputs[1], visit.to_date);

    const purposeInput =
      row.querySelector('input[placeholder*="purpose" i]') ||
      [...row.querySelectorAll('input.ant-input')].find((input) => !input.closest('.ant-picker'));

    if (!purposeInput) throw new Error('Visit row purpose input not found');
    setInputValue(purposeInput, String(visit.purpose || ''));
    await sleep(50);
  }

  async function clickPlusChildRow() {
    const table = findChildrenTable();
    if (!table) throw new Error('Children table not found');
    await clickPlusTableRow(table, 'Child row');
  }

  async function clickPlusVisitRow() {
    const table = findVisitHistoryTable();
    if (!table) throw new Error('Visit history table not found');
    await clickPlusTableRow(table, 'Visit history row');
  }

  return {
    sleep,
    waitFor,
    fillInput,
    fillAntDate,
    fillAntSelect,
    fillAntAutoComplete,
    fillRadioByContainer,
    fillRadioByQuestion,
    fillRadioByName,
    fillCheckboxById,
    fillCheckboxByText,
    findVisitHistoryTable,
    getTableDataRows,
    fillVisitHistoryRow,
    clickPlusChildRow,
    clickPlusVisitRow,
  };
  })();
})();


/* ===== lib/form-filler.js ===== */
/**
 * Orchestrates filling all e-Visa form sections from parsed YAML profile.
 */
(() => {
  if (globalThis.FormFiller) return;

  globalThis.FormFiller = (() => {
  function getH() {
    if (!globalThis.FieldHelpers) {
      throw new Error('FieldHelpers is not defined. Extension scripts may not have loaded in order.');
    }
    return globalThis.FieldHelpers;
  }

  async function runStep(name, fn, result) {
    try {
      globalThis.VietnamVisaLog?.step(name);
      await fn();
      result.filled += 1;
    } catch (err) {
      globalThis.VietnamVisaLog?.stepError(name, err);
      result.errors.push(`${name}: ${err.message}`);
    }
  }

  async function fillPersonal(data, result) {
    const p = data.personal_information || {};
    const H = getH();

    await runStep('surname', () => H.fillInput('basic_ttcnHo', p.surname), result);
    await runStep('given_name', () => H.fillInput('basic_ttcnDemVaTen', p.given_name), result);

    if (p.date_of_birth_mode) {
      await runStep('date_of_birth_mode', () => {
        const container = document.querySelector('.date-of-birth')?.closest('.grid')?.querySelector('.ant-radio-group');
        if (!container) throw new Error('Date of birth mode radio not found');
        const val = p.date_of_birth_mode === 'year_only' ? 'Y' : 'D';
        const radio = container.querySelector(`.ant-radio-input[value="${val}"]`);
        radio.closest('label')?.click();
      }, result);
    }

    await runStep('date_of_birth', () => H.fillAntDate('basic_ttcnNgayThangNamSinhStr', p.date_of_birth), result);
    await runStep('sex', () => H.fillAntSelect('basic_ttcnGioiTinh', p.sex, { searchable: false }), result);
    await runStep('nationality', () => H.fillAntSelect('basic_ttcnMaQt', p.nationality), result);
    await runStep('identity_card', () => H.fillInput('basic_ttcnCccd', p.identity_card), result);
    await runStep('email', () => H.fillInput('basic_ttcnEmail', p.email), result);

    if (p.agree_create_account !== undefined) {
      await runStep('agree_create_account', () => H.fillCheckboxByText('Agree to create account by email', p.agree_create_account), result);
    }

    await runStep('religion', () => H.fillInput('basic_ttcnTonGiao', p.religion), result);
    await runStep('place_of_birth', () => H.fillInput('basic_ttcnNoiSinh', p.place_of_birth), result);
    await runStep('confirm_email', () => H.fillInput('basic_ttcnConfirmEmail', p.email), result);

    if (p.used_other_passports !== undefined) {
      await runStep('used_other_passports', () => H.fillRadioByQuestion('Have you ever used any other passports', p.used_other_passports), result);
    }
    if (p.multiple_nationalities !== undefined) {
      await runStep('multiple_nationalities', () => H.fillRadioByQuestion('Do you have multiple nationalities', p.multiple_nationalities), result);
    }
    if (p.legal_violation !== undefined) {
      await runStep('legal_violation', () => H.fillRadioByQuestion('Violation of the Vietnamese laws', p.legal_violation), result);
    }
  }

  async function fillRequested(data, result) {
    const r = data.requested_information || {};
    const H = getH();

    if (r.entry_type) {
      await runStep('entry_type', () => H.fillRadioByName('#basic_nddnTtDeNghi', r.entry_type), result);
    }
    await runStep('valid_from', () => H.fillAntDate('basic_nddnTtdtTuNgayStr', r.valid_from), result);
    await runStep('valid_to', () => H.fillAntDate('basic_nddnTtdtDenNgayStr', r.valid_to), result);
  }

  async function fillPassport(data, result) {
    const p = data.passport_information || {};
    const H = getH();

    await runStep('passport_number', () => H.fillInput('basic_hcSo', p.number), result);
    await runStep('issuing_authority', () => H.fillInput('basic_hcNoiCap', p.issuing_authority), result);
    await runStep('passport_type', () => H.fillAntSelect('basic_hcLoai', p.type), result);
    await runStep('date_of_issue', () => H.fillAntDate('basic_hcNgayCapStr', p.date_of_issue), result);
    await runStep('expiry_date', () => H.fillAntDate('basic_hcGiaTriDenStr', p.expiry_date), result);

    if (p.other_valid_passports !== undefined) {
      await runStep('other_valid_passports', () => H.fillRadioByQuestion('Do you hold any other valid passports', p.other_valid_passports), result);
    }
  }

  async function fillContact(data, result) {
    const c = data.contact_information || {};
    const e = c.emergency_contact || {};
    const H = getH();

    await runStep('permanent_address', () => H.fillInput('basic_ttllDcThuongTru', c.permanent_address), result);
    await runStep('contact_address', () => H.fillInput('basic_ttllDcLienHe', c.contact_address), result);
    await runStep('telephone', () => H.fillInput('basic_ttllSdt', c.telephone), result);
    await runStep('emergency_name', () => H.fillInput('basic_ttllLlHoTen', e.full_name), result);
    await runStep('emergency_address', () => H.fillInput('basic_ttllLlNoiOHienTai', e.address), result);
    await runStep('emergency_phone', () => H.fillInput('basic_ttllLlSdt', e.telephone), result);
    await runStep('emergency_relationship', () => H.fillInput('basic_ttllLlQuanHe', e.relationship), result);
  }

  async function fillOccupation(data, result) {
    const o = data.occupation || {};
    const H = getH();

    if (o.occupation) {
      await runStep('occupation', () => H.fillAntSelect('basic_nnNgheNghiep', o.occupation, { searchable: false }), result);
    }
    await runStep('occupation_info', () => H.fillInput('basic_nnNgheNghiepHienTai', o.occupation_info), result);
    await runStep('company_name', () => H.fillInput('basic_nnTenCtyCq', o.company_name), result);
    await runStep('position', () => H.fillInput('basic_nnChucVu', o.position), result);
    await runStep('company_address', () => H.fillInput('basic_nnDiaChi', o.company_address), result);
    await runStep('company_phone', () => H.fillInput('basic_nnSdt', o.company_phone), result);
  }

  async function fillTrip(data, result) {
    const t = data.trip_information || {};
    const H = getH();

    await runStep('purpose_of_entry', () => H.fillAntSelect('basic_ttcdMucDich', t.purpose_of_entry), result);
    await runStep('intended_entry_date', () => H.fillAntDate('basic_ttcdThoiGianNcStr', t.intended_entry_date), result);
    await runStep('length_of_stay', () => H.fillInput('basic_ttcdSoNgayTamTru', t.length_of_stay_days), result);
    await runStep('phone_in_vietnam', () => H.fillInput('basic_ttcdSdt', t.phone_in_vietnam), result);
    await runStep('residential_address', () => H.fillAntAutoComplete('basic_ttcdDcTamTru', t.residential_address), result);

    if (t.province_city) {
      await runStep('province_city', () => H.fillAntSelect('basic_ttcdTinhTp', t.province_city), result);
      await H.sleep(1200);
    }

    if (t.ward_commune) {
      await runStep('ward_commune', async () => {
        await H.waitFor(() => {
          const input = document.getElementById('basic_ttcdPhuongXa');
          const select = input?.closest('.ant-select');
          return select && !select.classList.contains('ant-select-disabled');
        }, 5000);
        await H.fillAntSelect('basic_ttcdPhuongXa', t.ward_commune);
      }, result);
    }

    await runStep('border_gate_entry', () => H.fillAntSelect('basic_ttcdNcCuaKhau', t.border_gate_entry), result);
    await runStep('border_gate_exit', () => H.fillAntSelect('basic_ttcdXcCuaKhau', t.border_gate_exit), result);

    if (t.temporary_residence_commitment !== undefined) {
      await runStep('temporary_residence_commitment', () => H.fillCheckboxById('basic_ttcdCqTcCamDoan', t.temporary_residence_commitment), result);
    }
    if (t.contact_agency_in_vietnam !== undefined) {
      await runStep('contact_agency_in_vietnam', () => H.fillRadioByQuestion('Agency/Organization/Individual that the applicant plans to contact', t.contact_agency_in_vietnam), result);
    }
    if (t.visited_vietnam_last_year !== undefined) {
      await runStep('visited_vietnam_last_year', () => H.fillRadioByQuestion('Have you been to Viet Nam in the last 01 year', t.visited_vietnam_last_year), result);
      if (t.visited_vietnam_last_year) {
        await H.sleep(400);
        await fillVisitHistory(data, result);
      }
    }
    if (t.relatives_in_vietnam !== undefined) {
      await runStep('relatives_in_vietnam', () => H.fillRadioByQuestion('Do you have relatives who currently reside in Viet Nam', t.relatives_in_vietnam), result);
    }
  }

  async function fillVisitHistory(data, result) {
    const visits = data.vietnam_visits_last_year || [];
    const H = getH();

    if (!visits.length) {
      result.skipped.push('vietnam_visits_last_year (empty)');
      return;
    }

    const table = await H.waitFor(() => H.findVisitHistoryTable(), 5000);
    if (!table) {
      result.errors.push('visit_history: table not found after selecting Yes');
      return;
    }

    for (let i = 0; i < visits.length; i += 1) {
      const visit = visits[i];
      const prefix = `visit_${i + 1}`;

      if (i > 0) {
        await runStep(`${prefix}_add_row`, () => H.clickPlusVisitRow(), result);
        await H.sleep(300);
      }

      const rows = H.getTableDataRows(table);
      const row = rows[rows.length - 1];
      if (!row) {
        result.errors.push(`${prefix}: row not found`);
        continue;
      }

      await runStep(`${prefix}_from_date`, () => H.fillVisitHistoryRow(row, visit), result);
    }
  }

  async function fillChildren(data, result) {
    const children = data.accompanying_children || [];
    const H = getH();
    if (!children.length) {
      result.skipped.push('accompanying_children (empty)');
      return;
    }

    for (let i = 0; i < children.length; i += 1) {
      const child = children[i];
      const prefix = `child_${i + 1}`;

      await runStep(`${prefix}_add_row`, () => H.clickPlusChildRow(), result);
      await H.sleep(300);

      const rows = [...document.querySelectorAll('.ant-table-tbody tr')].filter(
        (r) => !r.classList.contains('ant-table-measure-row') && !r.classList.contains('ant-table-placeholder')
      );
      const row = rows[rows.length - 1];
      if (!row) {
        result.errors.push(`${prefix}: row not found after add`);
        continue;
      }

      const inputs = row.querySelectorAll('input.ant-input');
      const selects = row.querySelectorAll('.ant-select-selection-search-input');
      const dateInputs = row.querySelectorAll('.ant-picker-input input');

      if (child.full_name && inputs[0]) {
        await runStep(`${prefix}_name`, async () => {
          nativeInputValueSetter.call(inputs[0], child.full_name);
          inputs[0].dispatchEvent(new Event('input', { bubbles: true }));
          inputs[0].dispatchEvent(new Event('change', { bubbles: true }));
        }, result);
      }

      if (child.sex && selects[0]) {
        await runStep(`${prefix}_sex`, async () => {
          const id = selects[0].id || `child_sex_${i}`;
          if (!selects[0].id) selects[0].id = id;
          await H.fillAntSelect(id, child.sex, { searchable: false });
        }, result);
      }

      if (child.date_of_birth && dateInputs[0]) {
        await runStep(`${prefix}_dob`, async () => {
          dateInputs[0].removeAttribute('readonly');
          nativeInputValueSetter.call(dateInputs[0], child.date_of_birth);
          dateInputs[0].dispatchEvent(new Event('input', { bubbles: true }));
          dateInputs[0].dispatchEvent(new Event('change', { bubbles: true }));
          dateInputs[0].dispatchEvent(new Event('blur', { bubbles: true }));
        }, result);
      }

      result.skipped.push(`${prefix}_portrait (manual upload)`);
    }
  }

  const nativeInputValueSetter = Object.getOwnPropertyDescriptor(
    window.HTMLInputElement.prototype,
    'value'
  ).set;

  async function fillExpenses(data, result) {
    const e = data.trip_expenses || {};
    const H = getH();

    await runStep('intended_expenses', () => H.fillInput('basic_kpbhDuTinh', e.intended_expenses_usd), result);
    if (e.bought_insurance) {
      await runStep('bought_insurance', () => H.fillAntSelect('basic_kpbhMuaBaoHiem', e.bought_insurance, { searchable: false }), result);
    }
    if (e.expense_covered_by) {
      await runStep('expense_covered_by', () => H.fillAntSelect('basic_kpbhNguoiDamBao', e.expense_covered_by, { searchable: false }), result);
    }
  }

  async function fillDeclarations(data, result) {
    const d = data.declarations || {};
    const H = getH();
    if (d.final_declaration !== undefined) {
      await runStep('final_declaration', () => H.fillCheckboxByText('I hereby declare that the above statements are true', d.final_declaration), result);
    }
  }

  async function fillForm(profile) {
    getH();
    if (!globalThis.YamlParser) {
      throw new Error('YamlParser is not defined. Extension scripts may not have loaded in order.');
    }

    globalThis.VietnamVisaLog?.info('fillForm started');
    const result = { filled: 0, skipped: [], errors: [] };

    await fillPersonal(profile, result);
    await fillRequested(profile, result);
    await fillPassport(profile, result);
    await fillContact(profile, result);
    await fillOccupation(profile, result);
    await fillTrip(profile, result);
    await fillChildren(profile, result);
    await fillExpenses(profile, result);
    await fillDeclarations(profile, result);

    result.skipped.push('portrait_photo (manual upload)');
    result.skipped.push('passport_photo (manual upload)');

    globalThis.VietnamVisaLog?.info('fillForm completed', {
      filled: result.filled,
      errorCount: result.errors.length,
      skippedCount: result.skipped.length,
    });

    if (result.errors.length) {
      globalThis.VietnamVisaLog?.warn('fillForm errors', result.errors);
    }

    return result;
  }

  return { fillForm };
  })();
})();


/* ===== content/content.js ===== */
const FORM_MARKER_ID = 'basic_ttcnHo';
const TARGET_PATH = '/e-visa/foreigners';

(function initVietnamEvisaAutofill() {
  const log = () => globalThis.VietnamVisaLog || console;

  function ensureDependencies() {
    const missing = ['YamlParser', 'FieldHelpers', 'FormFiller'].filter(
      (name) => !globalThis[name]
    );
    if (missing.length) {
      throw new Error(`Missing modules: ${missing.join(', ')}`);
    }
  }

  if (globalThis.__VIETNAM_EVISA_AUTOFILL__) {
    log().info?.('content script re-activated');
    try {
      ensureDependencies();
    } catch (err) {
      log().error?.('dependency check failed on re-activate', err);
    }
    globalThis.__VIETNAM_EVISA_AUTOFILL__.activate();
    return;
  }

  let formObserver = null;
  let routeObserver = null;

  function isTargetPage() {
    return window.location.pathname.includes(TARGET_PATH);
  }

  function isFormPresent() {
    return Boolean(document.getElementById(FORM_MARKER_ID));
  }

  function watchForForm() {
    if (!isTargetPage()) return;

    if (isFormPresent()) {
      log().info?.('form detected and ready');
      return;
    }

    if (formObserver) return;

    formObserver = new MutationObserver(() => {
      if (isFormPresent()) {
        log().info?.('form detected and ready');
        formObserver.disconnect();
        formObserver = null;
      }
    });

    formObserver.observe(document.documentElement, { childList: true, subtree: true });
  }

  function watchRouteChanges() {
    if (routeObserver) return;

    let lastPath = `${window.location.pathname}${window.location.search}`;

    routeObserver = window.setInterval(() => {
      const currentPath = `${window.location.pathname}${window.location.search}`;
      if (currentPath === lastPath) return;

      lastPath = currentPath;

      if (formObserver) {
        formObserver.disconnect();
        formObserver = null;
      }

      if (isTargetPage()) {
        log().info?.('route changed to foreigners form', currentPath);
        watchForForm();
      }
    }, 500);
  }

  async function loadProfile() {
    log().debug?.('loading profile.yaml');
    const url = chrome.runtime.getURL('profile.yaml');
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Failed to load profile.yaml (${response.status})`);
    }
    const text = await response.text();
    ensureDependencies();
    const profile = globalThis.YamlParser.parse(text);
    log().debug?.('profile loaded', Object.keys(profile));
    return profile;
  }

  function parseDdMmYyyy(value) {
    const [day, month, year] = value.split('/').map(Number);
    return new Date(Date.UTC(year, month - 1, day));
  }

  function formatDdMmYyyy(date) {
    const day = String(date.getUTCDate()).padStart(2, '0');
    const month = String(date.getUTCMonth() + 1).padStart(2, '0');
    const year = date.getUTCFullYear();
    return `${day}/${month}/${year}`;
  }

  function isoToDdMmYyyy(iso) {
    const [year, month, day] = iso.split('-');
    return `${day}/${month}/${year}`;
  }

  function applyEntryDate(profile, entryDateIso) {
    if (!entryDateIso) return null;

    const entryDdMmYyyy = isoToDdMmYyyy(entryDateIso);
    const stayDays = Number.parseInt(profile.trip_information?.length_of_stay_days || '90', 10);
    const validToDate = parseDdMmYyyy(entryDdMmYyyy);
    validToDate.setUTCDate(validToDate.getUTCDate() + stayDays - 1);
    const validToDdMmYyyy = formatDdMmYyyy(validToDate);

    profile.requested_information = profile.requested_information || {};
    profile.trip_information = profile.trip_information || {};

    profile.requested_information.valid_from = entryDdMmYyyy;
    profile.requested_information.valid_to = validToDdMmYyyy;
    profile.trip_information.intended_entry_date = entryDdMmYyyy;

    log().info?.('applied entry date override', {
      entry: entryDdMmYyyy,
      validFrom: entryDdMmYyyy,
      validTo: validToDdMmYyyy,
      stayDays,
    });

    return {
      entry: entryDdMmYyyy,
      validFrom: entryDdMmYyyy,
      validTo: validToDdMmYyyy,
      stayDays,
    };
  }

  async function handleFillForm(entryDateIso) {
    log().info?.('handleFillForm called', { entryDateIso });

    if (!entryDateIso) {
      return { ok: false, error: 'Entry date is required. Open the extension popup and select a date.' };
    }

    if (!isTargetPage()) {
      log().warn?.('fill aborted: not on foreigners page');
      return { ok: false, error: 'Not on the foreigners application page.' };
    }

    if (!isFormPresent()) {
      log().warn?.('fill aborted: form not present');
      return {
        ok: false,
        error: 'Application form not found. Complete login and open the form first.',
      };
    }

    try {
      ensureDependencies();
      const profile = await loadProfile();
      const appliedDates = applyEntryDate(profile, entryDateIso);
      const result = await globalThis.FormFiller.fillForm(profile);
      result.appliedDates = appliedDates;
      return { ok: true, result };
    } catch (err) {
      log().error?.('handleFillForm failed', err.message, err.stack);
      return { ok: false, error: err.message };
    }
  }

  function activate() {
    if (isTargetPage()) {
      watchForForm();
    }
  }

  chrome.runtime.onMessage.addListener((message, _sender, sendResponse) => {
    if (message.action === 'ping') {
      let depsOk = true;
      let depsError = null;
      try {
        ensureDependencies();
      } catch (err) {
        depsOk = false;
        depsError = err.message;
        log().warn?.('ping: dependencies missing', depsError);
      }

      sendResponse({
        ok: true,
        onTargetPage: isTargetPage(),
        formReady: isFormPresent(),
        depsOk,
        depsError,
      });
      return false;
    }

    if (message.action === 'fillForm') {
      handleFillForm(message.entryDate)
        .then(sendResponse)
        .catch((err) => {
          log().error?.('fillForm listener failed', err.message, err.stack);
          sendResponse({ ok: false, error: err.message });
        });
      return true;
    }

    return false;
  });

  globalThis.__VIETNAM_EVISA_AUTOFILL__ = { activate };

  try {
    ensureDependencies();
    log().info?.('content script active', {
      path: window.location.pathname,
      deps: ['YamlParser', 'FieldHelpers', 'FormFiller'].filter((n) => Boolean(globalThis[n])),
    });
  } catch (err) {
    log().error?.('content script started with missing dependencies', err.message);
  }

  watchRouteChanges();
  activate();
})();
